proof:
suffices h_suff : ∀ p : ℕ, Nat.Prime p → p % 4 = 1 → p > 13 → ∃ n : ℕ, n^2 + 1 ≡ 0 [MOD p] ∧ p > 2 * n + Real.sqrt (2 * n) ∧ n ≤ (p - 1) / 2 by
  intro N
  obtain ⟨p, hp_prime, hp_mod, hp_gt⟩ : ∃ p : ℕ, Nat.Prime p ∧ p % 4 = 1 ∧ p > max 13 (N^2 + 1) := by
    exact Exists.imp ( by tauto ) ( Nat.exists_prime_gt_modEq_one ( Max.max 13 ( N ^ 2 + 1 ) ) ( by norm_num ) );
  obtain ⟨ n, hn₁, hn₂, hn₃ ⟩ := h_suff p hp_prime hp_mod ( lt_of_le_of_lt ( le_max_left _ _ ) hp_gt );
  refine' ⟨ n, _, p, hp_prime, Nat.dvd_of_mod_eq_zero hn₁, hn₂ ⟩;
  exact le_of_not_gt fun h => by have := Nat.dvd_of_mod_eq_zero hn₁; nlinarith [ Nat.le_of_dvd ( Nat.succ_pos _ ) this, le_max_right 13 ( N ^ 2 + 1 ) ] ;
intro p hp_prime hp_mod hp_gt_13
obtain ⟨n, hn⟩ : ∃ n : ℕ, n^2 + 1 ≡ 0 [MOD p] ∧ n ≤ (p - 1) / 2 := by
  obtain ⟨n, hn⟩ : ∃ n : ℕ, n^2 + 1 ≡ 0 [MOD p] ∧ n < p := by
    haveI := Fact.mk hp_prime; norm_num [ ← ZMod.natCast_eq_natCast_iff ] at *;
    obtain ⟨ x, hx ⟩ := ZMod.exists_sq_eq_neg_one_iff ( p := p );
    exact Exists.elim ( hx ( by rw [ hp_mod ] ; decide ) ) fun n hn => ⟨ n.val, by simpa [ sq, ← ZMod.intCast_eq_intCast_iff ] using by linear_combination' hn.symm, n.val_lt ⟩;
  cases le_or_gt n ( ( p - 1 ) / 2 ) <;> [ exact ⟨ n, hn.1, by assumption ⟩ ; exact ⟨ p - n, by simpa [ ← ZMod.natCast_eq_natCast_iff, Nat.cast_sub hn.2.le ] using hn.1, by omega ⟩ ];
obtain ⟨d, hd⟩ : ∃ d : ℕ, d = p - 2 * n ∧ d ≥ 1 ∧ d % 2 = 1 ∧ p ∣ d^2 + 4 := by
  refine' ⟨ p - 2 * n, rfl, _, _, _ ⟩;
  · omega;
  · omega;
  · have h_div : (p - 2 * n)^2 + 4 ≡ 0 [MOD p] := by
      simp_all +decide [ ← ZMod.natCast_eq_natCast_iff ];
      rw [ Nat.cast_sub ] <;> norm_num [ hn.1 ];
      · linear_combination' hn.1 * 4;
      · omega;
    exact Nat.dvd_of_mod_eq_zero h_div;
have h_key : d^2 + d > p := by
  by_cases hd_sq_lt_p : d^2 < p;
  · have hp_eq_d_sq_plus_4 : p = d^2 + 4 := by
      obtain ⟨ k, hk ⟩ := hd.2.2.2; nlinarith [ show k = 1 by nlinarith ] ;
    rcases d with ( _ | _ | _ | _ | _ | d ) <;> simp +arith +decide [ hp_eq_d_sq_plus_4 ] at *;
  · linarith;
have h_sqrt : (d : ℝ) > Real.sqrt (2 * n) := by
  exact Real.sqrt_lt' ( Nat.cast_pos.mpr hd.2.1 ) |>.2 ( by norm_cast; linarith [ Nat.sub_add_cancel ( show 2 * n ≤ p from by omega ) ] );
exact ⟨ n, hn.1, by linarith [ show ( p : ℝ ) = 2 * n + d by norm_cast; linarith [ Nat.sub_add_cancel ( show 2 * n ≤ p from by omega ) ] ], hn.2 ⟩

